create type user_role as enum ('admin','manager','student'); create table profiles(id uuid primary key references auth.users(id) on delete cascade,full_name text,role user_role default 'student',created_at timestamptz default now()); create table courses(id uuid primary key default gen_random_uuid(),title text not null,slug text unique not null,description text,category text,level text, published boolean default false); create table lessons(id uuid primary key default gen_random_uuid(),course_id uuid references courses(id) on delete cascade,title text not null,position int default 0,content text); create table progress(id uuid primary key default gen_random_uuid(),user_id uuid references profiles(id),lesson_id uuid references lessons(id),completed boolean default false,unique(user_id,lesson_id)); create table assignments(id uuid primary key default gen_random_uuid(),course_id uuid references courses(id),title text not null,description text); create table submissions(id uuid primary key default gen_random_uuid(),assignment_id uuid references assignments(id),user_id uuid references profiles(id),content text,status text default 'submitted',submitted_at timestamptz default now());
alter table profiles enable row level security; create policy "users can read own profile" on profiles for select using (auth.uid() = id); create policy "users can update own profile" on profiles for update using (auth.uid() = id);
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path = public as $$ begin insert into public.profiles (id, full_name) values (new.id, new.raw_user_meta_data->>'full_name'); return new; end; $$; create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();

